// client/src/pages/CartPage.jsx
import React from 'react';
import './CartPage.css'; // Create this CSS file

const CartPage = () => {
    // Placeholder cart items
    const cartItems = [
        { id: '1', name: 'Gaming Laptop', price: 1500, quantity: 1, imageUrl: 'https://placehold.co/100x100/cccccc/333333?text=Laptop' },
        { id: '2', name: 'Wireless Earbuds', price: 120, quantity: 2, imageUrl: 'https://placehold.co/100x100/cccccc/333333?text=Earbuds' },
    ];

    const calculateTotal = () => {
        return cartItems.reduce((total, item) => total + item.price * item.quantity, 0);
    };

    const handleUpdateQuantity = (id, newQuantity) => {
        console.log(`Update item ${id} quantity to ${newQuantity}`);
        // Implement logic to update quantity in state/backend
    };

    const handleRemoveItem = (id) => {
        console.log(`Remove item ${id} from cart`);
        // Implement logic to remove item from state/backend
    };

    const handleCheckout = () => {
        console.log('Proceeding to checkout...');
        // Implement checkout logic
    };

    return (
        <div className="cart-page container">
            <h1>Your Shopping Cart</h1>
            {cartItems.length === 0 ? (
                <p className="empty-cart-message">Your cart is empty. Start shopping now!</p>
            ) : (
                <div className="cart-content">
                    <div className="cart-items">
                        {cartItems.map(item => (
                            <div key={item.id} className="cart-item card">
                                <img src={item.imageUrl} alt={item.name} className="cart-item-image" />
                                <div className="cart-item-details">
                                    <h3>{item.name}</h3>
                                    <p>Price: ${item.price.toFixed(2)}</p>
                                    <div className="quantity-control">
                                        <label htmlFor={`quantity-${item.id}`}>Quantity:</label>
                                        <input
                                            type="number"
                                            id={`quantity-${item.id}`}
                                            min="1"
                                            value={item.quantity}
                                            onChange={(e) => handleUpdateQuantity(item.id, parseInt(e.target.value))}
                                        />
                                    </div>
                                    <p>Subtotal: ${(item.price * item.quantity).toFixed(2)}</p>
                                    <button onClick={() => handleRemoveItem(item.id)} className="btn btn-secondary remove-btn">Remove</button>
                                </div>
                            </div>
                        ))}
                    </div>
                    <div className="cart-summary card">
                        <h2>Order Summary</h2>
                        <p>Total Items: {cartItems.length}</p>
                        <p className="cart-total">Total: ${calculateTotal().toFixed(2)}</p>
                        <button onClick={handleCheckout} className="btn btn-accent checkout-btn">Proceed to Checkout</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default CartPage;
